import{_ as a,o as e,c as s,a as n}from"./app-c4d52e7d.js";const i={},t=n(`<h2 id="一、购买与连接服务器" tabindex="-1"><a class="header-anchor" href="#一、购买与连接服务器" aria-hidden="true">#</a> 一、购买与连接服务器</h2><h3 id="_1-购买服务器" tabindex="-1"><a class="header-anchor" href="#_1-购买服务器" aria-hidden="true">#</a> 1.购买服务器</h3><p>官方文档推荐的服务器要求CPU4核心内存8GB，所以我们要准备好一个4核8GB的服务器。(实测2核4GB的大概在5人左右就特别容易崩溃，CPU占用率在98%，内存占用很快就超过100%溢出，所以想要稳定最低最低也要2核6GB)</p><p>服务器购买建议阿里云、腾讯云、华为云等等供应商，建议选择大厂品牌，问题少一些。置顶评论区有优惠链接哦！</p><p>购买和启动服务器后需要做的操作是<strong>获取服务器的IP地址，设置root账号密码，还有开放8211的端口，8211的TCP协议和UDP协议都要开放</strong>。</p><h3 id="_2-连接服务器" tabindex="-1"><a class="header-anchor" href="#_2-连接服务器" aria-hidden="true">#</a> 2.连接服务器</h3><p>使用xshell连接服务器，xshell有官方的免费许可版本，下载网址放置顶评论区。下载打开后点击左上角文件新建，新建一个会话。</p><p>名称可以自定义，主机端写上自己的服务器IP，之后点击连接输入密码即可成功连接。</p><h2 id="二、安装steamcmd" tabindex="-1"><a class="header-anchor" href="#二、安装steamcmd" aria-hidden="true">#</a> 二、安装SteamCMD</h2><p>官方的文档链接放在评论区内。</p><p>服务器是不能在root用户上运行的，而且SteamCMD在root用上运行不安全，所以<em><strong>一定要创建新用户</strong></em>运行SteamCMD和服务器。</p><p><strong>创建新用户：</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">useradd</span> <span class="token parameter variable">-m</span> steam
<span class="token function">sudo</span> <span class="token function">passwd</span> steam
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>(steam账号的密码输入需要两遍)</p><p>赋予新用户权限</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">usermod</span> <span class="token parameter variable">-G</span> <span class="token function">sudo</span> steam
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>重启</p><p>进入新用户的home文件夹</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token parameter variable">-u</span> steam <span class="token parameter variable">-s</span>
<span class="token builtin class-name">cd</span> /home/steam
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>安装SteamCMD和依赖项：</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> add-apt-repository multiverse

<span class="token function">sudo</span> dpkg --add-architecture i386

<span class="token function">sudo</span> <span class="token function">apt</span> update

<span class="token function">sudo</span> <span class="token function">apt</span> <span class="token function">install</span> steamcmd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>安装Manually：</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt-get</span> <span class="token function">install</span> lib32gcc-s1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>新建文件夹，下载并解压SteamCMD</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> ~/Steam <span class="token operator">&amp;&amp;</span> <span class="token builtin class-name">cd</span> ~/Steam

<span class="token function">curl</span> <span class="token parameter variable">-sqL</span> <span class="token string">&quot;https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz&quot;</span> <span class="token operator">|</span> <span class="token function">tar</span> zxvf -
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="三、下载服务器" tabindex="-1"><a class="header-anchor" href="#三、下载服务器" aria-hidden="true">#</a> 三、下载服务器：</h2><p>运行steamcmd</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>./steamcmd.sh
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>下载服务器：</strong></p><p>匿名模式登陆：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>login anonymous
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>（显示OK后就登陆成功了）</p><p>下载服务器</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>app_update <span class="token number">2394010</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>还需要下载一个服务器依赖的包</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>app_update <span class="token number">1007</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>下载可能有点慢，多等等</p><p>退出SteamCMD</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>quit
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>建立库链接：</strong></p><p>新建.steam文件夹</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> ~/.steam
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>新建sdk64文件夹</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> ~/.steam/sdk64

<span class="token function">cp</span> ~/Steam/steamapps/common/Steamworks<span class="token punctuation">\\</span>SDK<span class="token punctuation">\\</span> Redist/linux64/steamclient.so ~/.steam/sdk64/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="四、配置运行服务器" tabindex="-1"><a class="header-anchor" href="#四、配置运行服务器" aria-hidden="true">#</a> 四、配置运行服务器</h2><p><strong>进入服务器文件夹：</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> ~/Steam/steamapps/common/PalServer
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>调整配置文件：</strong></p><p>默认配置文件是</p><aside> 💡 <p>[/Script/Pal.PalGameWorldSettings]</p><p>OptionSettings=(Difficulty=None,DayTimeSpeedRate=1.000000,NightTimeSpeedRate=1.000000,ExpRate=1.000000,PalCaptureRate=1.000000,PalSpawnNumRate=1.000000,PalDamageRateAttack=1.000000,PalDamageRateDefense=1.000000,PlayerDamageRateAttack=1.000000,PlayerDamageRateDefense=1.000000,PlayerStomachDecreaceRate=1.000000,PlayerStaminaDecreaceRate=1.000000,PlayerAutoHPRegeneRate=1.000000,PlayerAutoHpRegeneRateInSleep=1.000000,PalStomachDecreaceRate=1.000000,PalStaminaDecreaceRate=1.000000,PalAutoHPRegeneRate=1.000000,PalAutoHpRegeneRateInSleep=1.000000,BuildObjectDamageRate=1.000000,BuildObjectDeteriorationDamageRate=1.000000,CollectionDropRate=1.000000,CollectionObjectHpRate=1.000000,CollectionObjectRespawnSpeedRate=1.000000,EnemyDropItemRate=1.000000,DeathPenalty=All,bEnablePlayerToPlayerDamage=False,bEnableFriendlyFire=False,bEnableInvaderEnemy=True,bActiveUNKO=False,bEnableAimAssistPad=True,bEnableAimAssistKeyboard=False,DropItemMaxNum=3000,DropItemMaxNum_UNKO=100,BaseCampMaxNum=128,BaseCampWorkerMaxNum=15,DropItemAliveMaxHours=1.000000,bAutoResetGuildNoOnlinePlayers=False,AutoResetGuildTimeNoOnlinePlayers=72.000000,GuildPlayerMaxNum=20,PalEggDefaultHatchingTime=72.000000,WorkSpeedRate=1.000000,bIsMultiplay=False,bIsPvP=False,bCanPickupOtherGuildDeathPenaltyDrop=False,bEnableNonLoginPenalty=True,bEnableFastTravel=True,bIsStartLocationSelectByMap=True,bExistPlayerAfterLogout=False,bEnableDefenseOtherGuildPlayer=False,CoopPlayerMaxNum=4,ServerPlayerMaxNum=32,ServerName=&quot;Xi_Meng&quot;,ServerDescription=&quot;&quot;,AdminPassword=&quot;sqk001208&quot;,ServerPassword=&quot;&quot;,PublicPort=8211,PublicIP=”120.27.142.236 &quot;,RCONEnabled=False,RCONPort=25575,Region=&quot;China&quot;,bUseAuth=True,BanListURL=&quot;https://api.palworldgame.com/api/banlist.txt&quot;)</p></aside><p>把这段内容，修改最后几项的</p><p>ServerName服务器名</p><p>AdminPassword管理员密码</p><p>ServerPassword服务器密码</p><p>PublicIP 服务器IP</p><p>这几项修改后复制粘贴到下列文件中</p><p><strong>Pal/Saved/Config/LinuxServer/PalWorldSettings.ini</strong></p><p>注意要把值写在引号里，比如服务器密码：ServerPassword=&quot;&quot;改成ServerPassword=&quot;123456&quot;</p><p>如果想让自己的服务器能在社群服务器中被搜索到，可以在括号里加上</p><p>EpicApp=PalServer</p><p>简单的办法是复制好内容后，输入指令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> ~/Steam/steamapps/common/PalServer/Pal/Saved/Config/LinuxServer/PalWorldSettings.ini
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后把内容粘贴到新弹出来的框里</p><p>按ESC，输入 :wq 后按回车（注意要英文输入法，冒号也要打）</p><p><strong>运行服务器</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>./PalServer.sh
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="五、进入服务器" tabindex="-1"><a class="header-anchor" href="#五、进入服务器" aria-hidden="true">#</a> 五、进入服务器</h2><p>进入游戏后选择 加入多人游戏（专用服务器）</p><p>在最下面输入IP地址以及端口号即可进入服务器</p><p>如果设置了密码，在连一次后会弹窗提示没有输入密码，这时候再选择加入多人游戏（专用服务器），选择最近访问过的服务器列表，即可找到服务器输入密码进入服务器。</p>`,70),l=[t];function d(r,p){return e(),s("div",null,l)}const c=a(i,[["render",d],["__file","帕鲁.html.vue"]]);export{c as default};
